package com.ecommerce.search.config;

import org.apache.http.HttpHost;
import org.apache.http.auth.AuthScope;
import org.apache.http.auth.UsernamePasswordCredentials;
import org.apache.http.impl.client.BasicCredentialsProvider;
import org.apache.http.ssl.SSLContextBuilder;
import org.apache.http.ssl.SSLContexts;
import org.elasticsearch.client.RestClient;
import org.elasticsearch.client.RestClientBuilder;
import org.elasticsearch.client.RestHighLevelClient;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

import javax.annotation.PostConstruct;
import javax.net.ssl.SSLContext;
import java.io.File;
import java.io.FileInputStream;
import java.security.KeyStore;

@Configuration
public class ElasticsearchConfig {

    @Value("${elasticsearch.host}")
    private String host;

    @Value("${elasticsearch.port}")
    private int port;

    @Value("${elasticsearch.scheme}")
    private String scheme;

    @Value("${elasticsearch.username}")
    private String username;

    @Value("${elasticsearch.password}")
    private String password;

    @Value("${elasticsearch.truststore-path}")
    private String truststorePath;

    @Value("${elasticsearch.truststore-password}")
    private String truststorePassword;

    @Value("${elasticsearch.connection-timeout:5000}")
    private int connectionTimeout;

    @Value("${elasticsearch.socket-timeout:60000}")
    private int socketTimeout;

    @PostConstruct
    public void validateScheme() {
        if (!"https".equalsIgnoreCase(scheme)) {
            throw new IllegalArgumentException(
                "Elasticsearch connection must use HTTPS. Unencrypted HTTP connections are not allowed. " +
                "Current scheme: " + scheme + ". Please configure 'elasticsearch.scheme=https'."
            );
        }
    }

    @Bean(destroyMethod = "close")
    public RestHighLevelClient restHighLevelClient() throws Exception {
        // Enforce HTTPS - prevent unencrypted connections
        if (!"https".equalsIgnoreCase(scheme)) {
            throw new SecurityException(
                "Elasticsearch must be accessed over HTTPS. Unencrypted connections are prohibited."
            );
        }

        BasicCredentialsProvider credentialsProvider = new BasicCredentialsProvider();
        credentialsProvider.setCredentials(
            AuthScope.ANY,
            new UsernamePasswordCredentials(username, password)
        );

        // Load truststore for SSL/TLS
        KeyStore trustStore = KeyStore.getInstance("PKCS12");
        try (FileInputStream fis = new FileInputStream(new File(truststorePath))) {
            trustStore.load(fis, truststorePassword.toCharArray());
        }

        SSLContext sslContext = SSLContexts.custom()
            .loadTrustMaterial(trustStore, null)
            .build();

        RestClientBuilder builder = RestClient.builder(
            new HttpHost(host, port, "https")  // Always use HTTPS
        ).setHttpClientConfigCallback(httpClientBuilder ->
            httpClientBuilder
                .setDefaultCredentialsProvider(credentialsProvider)
                .setSSLContext(sslContext)
        ).setRequestConfigCallback(requestConfigBuilder ->
            requestConfigBuilder
                .setConnectTimeout(connectionTimeout)
                .setSocketTimeout(socketTimeout)
        );

        return new RestHighLevelClient(builder);
    }
}

