package com.ecommerce.search.service;

import com.fasterxml.jackson.databind.ObjectMapper;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.elasticsearch.action.admin.indices.delete.DeleteIndexRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.client.indices.CreateIndexRequest;
import org.elasticsearch.client.indices.CreateIndexResponse;
import org.elasticsearch.client.indices.GetIndexRequest;
import org.elasticsearch.common.settings.Settings;
import org.elasticsearch.common.xcontent.XContentType;
import org.springframework.stereotype.Service;

import javax.annotation.PostConstruct;
import java.io.IOException;
import java.util.HashMap;
import java.util.Map;

@Service
@RequiredArgsConstructor
@Slf4j
public class IndexManagementService {

    public static final String PRODUCT_INDEX = "products";
    public static final String SEARCH_QUERY_INDEX = "search_queries";

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    @PostConstruct
    public void initializeIndices() {
        try {
            createProductIndexIfNotExists();
            createSearchQueryIndexIfNotExists();
            log.info("Elasticsearch indices initialized successfully");
        } catch (IOException e) {
            log.error("Failed to initialize Elasticsearch indices", e);
            throw new RuntimeException("Failed to initialize Elasticsearch indices", e);
        }
    }

    private void createProductIndexIfNotExists() throws IOException {
        if (indexExists(PRODUCT_INDEX)) {
            log.info("Product index already exists");
            return;
        }

        CreateIndexRequest request = new CreateIndexRequest(PRODUCT_INDEX);

        request.settings(Settings.builder()
            .put("index.number_of_shards", 3)
            .put("index.number_of_replicas", 1)
            .put("analysis.analyzer.product_analyzer.type", "custom")
            .put("analysis.analyzer.product_analyzer.tokenizer", "standard")
            .putList("analysis.analyzer.product_analyzer.filter", "lowercase", "stop", "snowball")
            .put("analysis.analyzer.autocomplete_analyzer.type", "custom")
            .put("analysis.analyzer.autocomplete_analyzer.tokenizer", "autocomplete_tokenizer")
            .put("analysis.tokenizer.autocomplete_tokenizer.type", "edge_ngram")
            .put("analysis.tokenizer.autocomplete_tokenizer.min_gram", 2)
            .put("analysis.tokenizer.autocomplete_tokenizer.max_gram", 20)
            .putList("analysis.tokenizer.autocomplete_tokenizer.token_chars", "letter", "digit")
        );

        Map<String, Object> mapping = new HashMap<>();
        Map<String, Object> properties = new HashMap<>();

        properties.put("name", Map.of(
            "type", "text",
            "analyzer", "product_analyzer",
            "fields", Map.of(
                "keyword", Map.of("type", "keyword"),
                "autocomplete", Map.of("type", "text", "analyzer", "autocomplete_analyzer", "search_analyzer", "standard")
            )
        ));

        properties.put("description", Map.of(
            "type", "text",
            "analyzer", "product_analyzer"
        ));

        properties.put("price", Map.of("type", "double"));
        properties.put("category", Map.of(
            "type", "text",
            "fields", Map.of("keyword", Map.of("type", "keyword"))
        ));
        properties.put("brand", Map.of(
            "type", "text",
            "fields", Map.of("keyword", Map.of("type", "keyword"))
        ));
        properties.put("tags", Map.of(
            "type", "text",
            "fields", Map.of("keyword", Map.of("type", "keyword"))
        ));
        properties.put("attributes", Map.of("type", "object", "enabled", true));
        properties.put("imageUrl", Map.of("type", "keyword"));
        properties.put("rating", Map.of("type", "double"));
        properties.put("reviewCount", Map.of("type", "integer"));
        properties.put("inStock", Map.of("type", "boolean"));
        properties.put("createdAt", Map.of("type", "date"));
        properties.put("updatedAt", Map.of("type", "date"));

        mapping.put("properties", properties);

        String mappingJson = objectMapper.writeValueAsString(mapping);
        request.mapping(mappingJson, XContentType.JSON);

        CreateIndexResponse response = client.indices().create(request, RequestOptions.DEFAULT);
        log.info("Product index created: {}", response.isAcknowledged());
    }

    private void createSearchQueryIndexIfNotExists() throws IOException {
        if (indexExists(SEARCH_QUERY_INDEX)) {
            log.info("Search query index already exists");
            return;
        }

        CreateIndexRequest request = new CreateIndexRequest(SEARCH_QUERY_INDEX);

        request.settings(Settings.builder()
            .put("index.number_of_shards", 2)
            .put("index.number_of_replicas", 1)
        );

        Map<String, Object> mapping = new HashMap<>();
        Map<String, Object> properties = new HashMap<>();

        properties.put("queryText", Map.of("type", "text", "fields", Map.of("keyword", Map.of("type", "keyword"))));
        properties.put("customerId", Map.of("type", "keyword"));
        properties.put("sessionId", Map.of("type", "keyword"));
        properties.put("filters", Map.of("type", "object", "enabled", true));
        properties.put("resultsCount", Map.of("type", "integer"));
        properties.put("timestamp", Map.of("type", "date"));
        properties.put("ipAddress", Map.of("type", "keyword"));
        properties.put("userAgent", Map.of("type", "text"));

        mapping.put("properties", properties);

        String mappingJson = objectMapper.writeValueAsString(mapping);
        request.mapping(mappingJson, XContentType.JSON);

        CreateIndexResponse response = client.indices().create(request, RequestOptions.DEFAULT);
        log.info("Search query index created: {}", response.isAcknowledged());
    }

    public boolean indexExists(String indexName) throws IOException {
        GetIndexRequest request = new GetIndexRequest(indexName);
        return client.indices().exists(request, RequestOptions.DEFAULT);
    }

    public void deleteIndex(String indexName) throws IOException {
        if (indexExists(indexName)) {
            DeleteIndexRequest request = new DeleteIndexRequest(indexName);
            client.indices().delete(request, RequestOptions.DEFAULT);
            log.info("Index {} deleted", indexName);
        }
    }
}

