package com.ecommerce.search.service;

import com.ecommerce.search.model.Product;
import com.ecommerce.search.model.SearchRequest;
import com.ecommerce.search.model.SearchResponse;
import com.ecommerce.search.model.SearchResponse.FacetEntry;
import com.fasterxml.jackson.databind.ObjectMapper;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.elasticsearch.action.search.SearchScrollRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.text.Text;
import org.elasticsearch.common.unit.TimeValue;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.MultiMatchQueryBuilder;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.histogram.Histogram;
import org.elasticsearch.search.aggregations.bucket.histogram.HistogramAggregationBuilder;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.aggregations.bucket.terms.TermsAggregationBuilder;
import org.elasticsearch.search.aggregations.metrics.Avg;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.fetch.subphase.highlight.HighlightBuilder;
import org.elasticsearch.search.fetch.subphase.highlight.HighlightField;
import org.elasticsearch.search.sort.SortOrder;
import org.elasticsearch.search.suggest.SuggestBuilder;
import org.elasticsearch.search.suggest.SuggestBuilders;
import org.elasticsearch.search.suggest.completion.CompletionSuggestion;
import org.elasticsearch.search.suggest.phrase.PhraseSuggestion;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.util.*;
import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
@Slf4j
public class ProductSearchService {

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;
    private final SearchQueryService searchQueryService;

    public SearchResponse search(SearchRequest searchRequest, String customerId, String sessionId,
                                  String ipAddress, String userAgent) throws IOException {
        org.elasticsearch.action.search.SearchRequest esRequest =
            new org.elasticsearch.action.search.SearchRequest(IndexManagementService.PRODUCT_INDEX);

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        // Build query
        BoolQueryBuilder boolQuery = buildQuery(searchRequest);
        sourceBuilder.query(boolQuery);

        // Pagination
        int page = Math.max(searchRequest.getPage(), 0);
        int size = searchRequest.getSize() > 0 ? Math.min(searchRequest.getSize(), 100) : 20;
        sourceBuilder.from(page * size);
        sourceBuilder.size(size);

        // Sorting
        applySorting(sourceBuilder, searchRequest);

        // Highlighting
        applyHighlighting(sourceBuilder);

        // Faceted aggregations
        applyAggregations(sourceBuilder);

        esRequest.source(sourceBuilder);

        org.elasticsearch.action.search.SearchResponse esResponse =
            client.search(esRequest, RequestOptions.DEFAULT);

        // Parse results
        List<Product> products = parseProducts(esResponse);
        Map<String, List<FacetEntry>> facets = parseFacets(esResponse);
        long totalHits = esResponse.getHits().getTotalHits().value;
        long totalPages = (totalHits + size - 1) / size;

        // Log search query asynchronously
        searchQueryService.logSearchQuery(
            searchRequest.getQuery(),
            customerId,
            sessionId,
            buildFiltersMap(searchRequest),
            (int) totalHits,
            ipAddress,
            userAgent
        );

        return SearchResponse.builder()
            .products(products)
            .totalHits(totalHits)
            .page(page)
            .size(size)
            .totalPages(totalPages)
            .facets(facets)
            .build();
    }

    public SearchResponse autocomplete(String prefix) throws IOException {
        org.elasticsearch.action.search.SearchRequest esRequest =
            new org.elasticsearch.action.search.SearchRequest(IndexManagementService.PRODUCT_INDEX);

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery()
            .should(QueryBuilders.matchPhrasePrefixQuery("name", prefix).maxExpansions(10))
            .should(QueryBuilders.matchQuery("name.autocomplete", prefix))
            .minimumShouldMatch(1);

        sourceBuilder.query(boolQuery);
        sourceBuilder.size(10);
        sourceBuilder.fetchSource(new String[]{"name", "category", "brand", "price", "imageUrl"}, null);

        esRequest.source(sourceBuilder);

        org.elasticsearch.action.search.SearchResponse esResponse =
            client.search(esRequest, RequestOptions.DEFAULT);

        List<Product> products = parseProducts(esResponse);

        return SearchResponse.builder()
            .products(products)
            .totalHits(esResponse.getHits().getTotalHits().value)
            .build();
    }

    public List<String> getSuggestions(String query) throws IOException {
        org.elasticsearch.action.search.SearchRequest esRequest =
            new org.elasticsearch.action.search.SearchRequest(IndexManagementService.PRODUCT_INDEX);

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.size(0);

        // Use term suggestion for spell correction
        SuggestBuilder suggestBuilder = new SuggestBuilder();
        suggestBuilder.addSuggestion("spell-suggestion",
            SuggestBuilders.phraseSuggestion("name")
                .text(query)
                .maxErrors(2f)
                .size(5)
        );

        sourceBuilder.suggest(suggestBuilder);
        esRequest.source(sourceBuilder);

        org.elasticsearch.action.search.SearchResponse esResponse =
            client.search(esRequest, RequestOptions.DEFAULT);

        List<String> suggestions = new ArrayList<>();
        if (esResponse.getSuggest() != null) {
            PhraseSuggestion phraseSuggestion = esResponse.getSuggest().getSuggestion("spell-suggestion");
            if (phraseSuggestion != null) {
                for (PhraseSuggestion.Entry entry : phraseSuggestion.getEntries()) {
                    for (PhraseSuggestion.Entry.Option option : entry.getOptions()) {
                        suggestions.add(option.getText().string());
                    }
                }
            }
        }

        return suggestions;
    }

    public SearchResponse searchSimilar(String productId) throws IOException {
        org.elasticsearch.action.search.SearchRequest esRequest =
            new org.elasticsearch.action.search.SearchRequest(IndexManagementService.PRODUCT_INDEX);

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        sourceBuilder.query(QueryBuilders.moreLikeThisQuery(
            new String[]{"name", "description", "category", "tags"},
            null,
            new org.elasticsearch.index.query.MoreLikeThisQueryBuilder.Item[]{
                new org.elasticsearch.index.query.MoreLikeThisQueryBuilder.Item(
                    IndexManagementService.PRODUCT_INDEX, productId
                )
            }
        ).minTermFreq(1).minDocFreq(1).maxQueryTerms(12));

        sourceBuilder.size(10);
        esRequest.source(sourceBuilder);

        org.elasticsearch.action.search.SearchResponse esResponse =
            client.search(esRequest, RequestOptions.DEFAULT);

        List<Product> products = parseProducts(esResponse);

        return SearchResponse.builder()
            .products(products)
            .totalHits(esResponse.getHits().getTotalHits().value)
            .build();
    }

    private BoolQueryBuilder buildQuery(SearchRequest searchRequest) {
        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        // Full-text search
        if (searchRequest.getQuery() != null && !searchRequest.getQuery().trim().isEmpty()) {
            String sanitizedQuery = sanitizeQuery(searchRequest.getQuery());
            MultiMatchQueryBuilder multiMatch = QueryBuilders.multiMatchQuery(sanitizedQuery,
                    "name^3", "description^2", "category", "brand", "tags")
                .type(MultiMatchQueryBuilder.Type.BEST_FIELDS)
                .fuzziness("AUTO")
                .minimumShouldMatch("75%");
            boolQuery.must(multiMatch);
        } else {
            boolQuery.must(QueryBuilders.matchAllQuery());
        }

        // Category filter
        if (searchRequest.getCategory() != null && !searchRequest.getCategory().isEmpty()) {
            boolQuery.filter(QueryBuilders.termQuery("category.keyword", searchRequest.getCategory()));
        }

        // Brand filter
        if (searchRequest.getBrand() != null && !searchRequest.getBrand().isEmpty()) {
            boolQuery.filter(QueryBuilders.termQuery("brand.keyword", searchRequest.getBrand()));
        }

        // Price range filter
        if (searchRequest.getMinPrice() != null || searchRequest.getMaxPrice() != null) {
            var rangeQuery = QueryBuilders.rangeQuery("price");
            if (searchRequest.getMinPrice() != null) {
                rangeQuery.gte(searchRequest.getMinPrice());
            }
            if (searchRequest.getMaxPrice() != null) {
                rangeQuery.lte(searchRequest.getMaxPrice());
            }
            boolQuery.filter(rangeQuery);
        }

        // In stock filter
        if (searchRequest.getInStock() != null) {
            boolQuery.filter(QueryBuilders.termQuery("inStock", searchRequest.getInStock()));
        }

        // Rating filter
        if (searchRequest.getMinRating() != null) {
            boolQuery.filter(QueryBuilders.rangeQuery("rating").gte(searchRequest.getMinRating()));
        }

        // Tags filter
        if (searchRequest.getTags() != null && !searchRequest.getTags().isEmpty()) {
            for (String tag : searchRequest.getTags()) {
                boolQuery.filter(QueryBuilders.termQuery("tags.keyword", tag));
            }
        }

        // Attributes filter
        if (searchRequest.getAttributes() != null && !searchRequest.getAttributes().isEmpty()) {
            for (Map.Entry<String, String> attr : searchRequest.getAttributes().entrySet()) {
                boolQuery.filter(QueryBuilders.termQuery("attributes." + attr.getKey() + ".keyword", attr.getValue()));
            }
        }

        return boolQuery;
    }

    private void applySorting(SearchSourceBuilder sourceBuilder, SearchRequest searchRequest) {
        if (searchRequest.getSortField() != null && !searchRequest.getSortField().isEmpty()) {
            String sortField = searchRequest.getSortField();
            SortOrder sortOrder = "desc".equalsIgnoreCase(searchRequest.getSortOrder())
                ? SortOrder.DESC : SortOrder.ASC;

            switch (sortField) {
                case "price":
                    sourceBuilder.sort("price", sortOrder);
                    break;
                case "rating":
                    sourceBuilder.sort("rating", sortOrder);
                    break;
                case "name":
                    sourceBuilder.sort("name.keyword", sortOrder);
                    break;
                case "createdAt":
                    sourceBuilder.sort("createdAt", sortOrder);
                    break;
                default:
                    sourceBuilder.sort("_score", SortOrder.DESC);
            }
        } else {
            sourceBuilder.sort("_score", SortOrder.DESC);
        }
    }

    private void applyHighlighting(SearchSourceBuilder sourceBuilder) {
        HighlightBuilder highlightBuilder = new HighlightBuilder();
        highlightBuilder.field("name").preTags("<em>").postTags("</em>");
        highlightBuilder.field("description").preTags("<em>").postTags("</em>")
            .fragmentSize(150).numOfFragments(3);
        sourceBuilder.highlighter(highlightBuilder);
    }

    private void applyAggregations(SearchSourceBuilder sourceBuilder) {
        // Category facet
        TermsAggregationBuilder categoryAgg = AggregationBuilders
            .terms("categories")
            .field("category.keyword")
            .size(50);
        sourceBuilder.aggregation(categoryAgg);

        // Brand facet
        TermsAggregationBuilder brandAgg = AggregationBuilders
            .terms("brands")
            .field("brand.keyword")
            .size(50);
        sourceBuilder.aggregation(brandAgg);

        // Price range facet
        HistogramAggregationBuilder priceAgg = AggregationBuilders
            .histogram("price_ranges")
            .field("price")
            .interval(50)
            .minDocCount(1);
        sourceBuilder.aggregation(priceAgg);

        // Rating facet
        HistogramAggregationBuilder ratingAgg = AggregationBuilders
            .histogram("ratings")
            .field("rating")
            .interval(1)
            .minDocCount(1);
        sourceBuilder.aggregation(ratingAgg);

        // Tags facet
        TermsAggregationBuilder tagsAgg = AggregationBuilders
            .terms("tags")
            .field("tags.keyword")
            .size(30);
        sourceBuilder.aggregation(tagsAgg);

        // In stock facet
        TermsAggregationBuilder stockAgg = AggregationBuilders
            .terms("in_stock")
            .field("inStock");
        sourceBuilder.aggregation(stockAgg);

        // Average price
        sourceBuilder.aggregation(AggregationBuilders.avg("avg_price").field("price"));
        sourceBuilder.aggregation(AggregationBuilders.avg("avg_rating").field("rating"));
    }

    private List<Product> parseProducts(org.elasticsearch.action.search.SearchResponse esResponse) {
        List<Product> products = new ArrayList<>();
        for (SearchHit hit : esResponse.getHits().getHits()) {
            try {
                Product product = objectMapper.readValue(hit.getSourceAsString(), Product.class);
                product.setId(hit.getId());

                // Apply highlights if available
                Map<String, HighlightField> highlights = hit.getHighlightFields();
                if (highlights.containsKey("name")) {
                    String highlightedName = Arrays.stream(highlights.get("name").getFragments())
                        .map(Text::string)
                        .collect(Collectors.joining(" "));
                    // Store highlighted name - could be used in response
                }

                products.add(product);
            } catch (IOException e) {
                log.error("Failed to parse product from search hit: {}", hit.getId(), e);
            }
        }
        return products;
    }

    private Map<String, List<FacetEntry>> parseFacets(org.elasticsearch.action.search.SearchResponse esResponse) {
        Map<String, List<FacetEntry>> facets = new LinkedHashMap<>();

        if (esResponse.getAggregations() == null) {
            return facets;
        }

        // Parse terms aggregations
        parseTermsAggregation(esResponse, "categories", facets);
        parseTermsAggregation(esResponse, "brands", facets);
        parseTermsAggregation(esResponse, "tags", facets);
        parseTermsAggregation(esResponse, "in_stock", facets);

        // Parse histogram aggregations
        parseHistogramAggregation(esResponse, "price_ranges", facets);
        parseHistogramAggregation(esResponse, "ratings", facets);

        return facets;
    }

    private void parseTermsAggregation(org.elasticsearch.action.search.SearchResponse esResponse,
                                        String aggName, Map<String, List<FacetEntry>> facets) {
        try {
            Terms terms = esResponse.getAggregations().get(aggName);
            if (terms != null) {
                List<FacetEntry> entries = terms.getBuckets().stream()
                    .map(bucket -> FacetEntry.builder()
                        .key(bucket.getKeyAsString())
                        .count(bucket.getDocCount())
                        .build())
                    .collect(Collectors.toList());
                facets.put(aggName, entries);
            }
        } catch (Exception e) {
            log.debug("Could not parse aggregation: {}", aggName);
        }
    }

    private void parseHistogramAggregation(org.elasticsearch.action.search.SearchResponse esResponse,
                                            String aggName, Map<String, List<FacetEntry>> facets) {
        try {
            Histogram histogram = esResponse.getAggregations().get(aggName);
            if (histogram != null) {
                List<FacetEntry> entries = histogram.getBuckets().stream()
                    .map(bucket -> FacetEntry.builder()
                        .key(bucket.getKeyAsString())
                        .count(bucket.getDocCount())
                        .build())
                    .collect(Collectors.toList());
                facets.put(aggName, entries);
            }
        } catch (Exception e) {
            log.debug("Could not parse histogram aggregation: {}", aggName);
        }
    }

    private String sanitizeQuery(String query) {
        if (query == null) return "";
        // Remove special Elasticsearch query characters to prevent injection
        return query.replaceAll("[+\\-=&|><!(){}\\[\\]^\"~*?:\\\\/]", " ").trim();
    }

    private Map<String, String> buildFiltersMap(SearchRequest searchRequest) {
        Map<String, String> filters = new HashMap<>();
        if (searchRequest.getCategory() != null) filters.put("category", searchRequest.getCategory());
        if (searchRequest.getBrand() != null) filters.put("brand", searchRequest.getBrand());
        if (searchRequest.getMinPrice() != null) filters.put("minPrice", searchRequest.getMinPrice().toString());
        if (searchRequest.getMaxPrice() != null) filters.put("maxPrice", searchRequest.getMaxPrice().toString());
        if (searchRequest.getInStock() != null) filters.put("inStock", searchRequest.getInStock().toString());
        if (searchRequest.getMinRating() != null) filters.put("minRating", searchRequest.getMinRating().toString());
        return filters;
    }
}

