package com.ecommerce.search.service;

import com.ecommerce.search.model.SearchQuery;
import com.fasterxml.jackson.databind.ObjectMapper;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.sort.SortOrder;
import org.springframework.scheduling.annotation.Async;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.Instant;
import java.util.*;
import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
@Slf4j
public class SearchQueryService {

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    @Async
    public void logSearchQuery(String queryText, String customerId, String sessionId,
                                Map<String, String> filters, int resultsCount,
                                String ipAddress, String userAgent) {
        try {
            SearchQuery searchQuery = SearchQuery.builder()
                .id(UUID.randomUUID().toString())
                .queryText(queryText)
                .customerId(customerId)
                .sessionId(sessionId)
                .filters(filters)
                .resultsCount(resultsCount)
                .timestamp(Instant.now())
                .ipAddress(ipAddress)
                .userAgent(userAgent)
                .build();

            String json = objectMapper.writeValueAsString(searchQuery);

            IndexRequest request = new IndexRequest(IndexManagementService.SEARCH_QUERY_INDEX)
                .id(searchQuery.getId())
                .source(json, XContentType.JSON);

            client.index(request, RequestOptions.DEFAULT);
            log.debug("Search query logged: {}", queryText);
        } catch (Exception e) {
            log.error("Failed to log search query", e);
        }
    }

    public List<String> getPopularSearches(int size) throws IOException {
        SearchRequest request = new SearchRequest(IndexManagementService.SEARCH_QUERY_INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.size(0);

        sourceBuilder.aggregation(
            AggregationBuilders.terms("popular_queries")
                .field("queryText.keyword")
                .size(size)
                .minDocCount(2)
        );

        request.source(sourceBuilder);
        SearchResponse response = client.search(request, RequestOptions.DEFAULT);

        Terms terms = response.getAggregations().get("popular_queries");
        return terms.getBuckets().stream()
            .map(bucket -> bucket.getKeyAsString())
            .collect(Collectors.toList());
    }

    public List<String> getRecentSearches(String customerId, int size) throws IOException {
        SearchRequest request = new SearchRequest(IndexManagementService.SEARCH_QUERY_INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        sourceBuilder.query(QueryBuilders.termQuery("customerId", customerId));
        sourceBuilder.sort("timestamp", SortOrder.DESC);
        sourceBuilder.size(size);
        sourceBuilder.fetchSource(new String[]{"queryText"}, null);

        request.source(sourceBuilder);
        SearchResponse response = client.search(request, RequestOptions.DEFAULT);

        Set<String> seen = new LinkedHashSet<>();
        for (var hit : response.getHits().getHits()) {
            Map<String, Object> source = hit.getSourceAsMap();
            String queryText = (String) source.get("queryText");
            if (queryText != null && !queryText.isEmpty()) {
                seen.add(queryText);
            }
        }

        return new ArrayList<>(seen);
    }

    public Map<String, Object> getSearchAnalytics(String startDate, String endDate) throws IOException {
        SearchRequest request = new SearchRequest(IndexManagementService.SEARCH_QUERY_INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.size(0);

        sourceBuilder.query(QueryBuilders.rangeQuery("timestamp")
            .gte(startDate)
            .lte(endDate));

        sourceBuilder.aggregation(
            AggregationBuilders.terms("top_queries")
                .field("queryText.keyword")
                .size(20)
        );

        sourceBuilder.aggregation(
            AggregationBuilders.terms("zero_result_queries")
                .field("queryText.keyword")
                .size(20)
                .subAggregation(
                    AggregationBuilders.filter("zero_results",
                        QueryBuilders.termQuery("resultsCount", 0))
                )
        );

        sourceBuilder.aggregation(
            AggregationBuilders.avg("avg_results_count").field("resultsCount")
        );

        request.source(sourceBuilder);
        SearchResponse response = client.search(request, RequestOptions.DEFAULT);

        Map<String, Object> analytics = new HashMap<>();
        analytics.put("totalSearches", response.getHits().getTotalHits().value);

        Terms topQueries = response.getAggregations().get("top_queries");
        analytics.put("topQueries", topQueries.getBuckets().stream()
            .map(b -> Map.of("query", b.getKeyAsString(), "count", b.getDocCount()))
            .collect(Collectors.toList()));

        return analytics;
    }
}

