package com.ecommerce.search.controller;

import com.ecommerce.search.model.BulkIndexRequest;
import com.ecommerce.search.model.Product;
import com.ecommerce.search.service.ProductIndexingService;
import lombok.RequiredArgsConstructor;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import javax.validation.Valid;
import java.io.IOException;
import java.util.Map;
import java.util.Optional;

@RestController
@RequestMapping("/api/products")
@RequiredArgsConstructor
public class ProductController {

    private final ProductIndexingService productIndexingService;

    @PostMapping
    public ResponseEntity<Map<String, String>> indexProduct(@Valid @RequestBody Product product) throws IOException {
        String id = productIndexingService.indexProduct(product);
        return ResponseEntity.status(HttpStatus.CREATED)
            .body(Map.of("id", id, "status", "CREATED"));
    }

    @PostMapping("/bulk")
    public ResponseEntity<Map<String, String>> bulkIndex(@Valid @RequestBody BulkIndexRequest request) throws IOException {
        Map<String, String> results = productIndexingService.bulkIndexProducts(request.getProducts());
        return ResponseEntity.ok(results);
    }

    @GetMapping("/{id}")
    public ResponseEntity<Product> getProduct(@PathVariable String id) throws IOException {
        Optional<Product> product = productIndexingService.getProduct(id);
        return product.map(ResponseEntity::ok)
            .orElse(ResponseEntity.notFound().build());
    }

    @PutMapping("/{id}")
    public ResponseEntity<Map<String, String>> updateProduct(@PathVariable String id,
                                                              @Valid @RequestBody Product product) throws IOException {
        String result = productIndexingService.updateProduct(id, product);
        return ResponseEntity.ok(Map.of("id", id, "result", result));
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Map<String, String>> deleteProduct(@PathVariable String id) throws IOException {
        String result = productIndexingService.deleteProduct(id);
        return ResponseEntity.ok(Map.of("id", id, "result", result));
    }
}

