package com.ecommerce.search.controller;

import com.ecommerce.search.model.SearchRequest;
import com.ecommerce.search.model.SearchResponse;
import com.ecommerce.search.service.ProductSearchService;
import com.ecommerce.search.service.SearchQueryService;
import lombok.RequiredArgsConstructor;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import javax.servlet.http.HttpServletRequest;
import java.io.IOException;
import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/search")
@RequiredArgsConstructor
public class SearchController {

    private final ProductSearchService productSearchService;
    private final SearchQueryService searchQueryService;

    @PostMapping
    public ResponseEntity<SearchResponse> search(
            @RequestBody SearchRequest searchRequest,
            @RequestHeader(value = "X-Customer-Id", required = false) String customerId,
            @RequestHeader(value = "X-Session-Id", required = false) String sessionId,
            HttpServletRequest httpRequest) throws IOException {

        String ipAddress = httpRequest.getRemoteAddr();
        String userAgent = httpRequest.getHeader("User-Agent");

        SearchResponse response = productSearchService.search(
            searchRequest, customerId, sessionId, ipAddress, userAgent
        );
        return ResponseEntity.ok(response);
    }

    @GetMapping("/autocomplete")
    public ResponseEntity<SearchResponse> autocomplete(@RequestParam String prefix) throws IOException {
        SearchResponse response = productSearchService.autocomplete(prefix);
        return ResponseEntity.ok(response);
    }

    @GetMapping("/suggestions")
    public ResponseEntity<List<String>> suggestions(@RequestParam String query) throws IOException {
        List<String> suggestions = productSearchService.getSuggestions(query);
        return ResponseEntity.ok(suggestions);
    }

    @GetMapping("/similar/{productId}")
    public ResponseEntity<SearchResponse> similarProducts(@PathVariable String productId) throws IOException {
        SearchResponse response = productSearchService.searchSimilar(productId);
        return ResponseEntity.ok(response);
    }

    @GetMapping("/popular")
    public ResponseEntity<List<String>> popularSearches(
            @RequestParam(defaultValue = "10") int size) throws IOException {
        List<String> popular = searchQueryService.getPopularSearches(size);
        return ResponseEntity.ok(popular);
    }

    @GetMapping("/recent")
    public ResponseEntity<List<String>> recentSearches(
            @RequestHeader("X-Customer-Id") String customerId,
            @RequestParam(defaultValue = "10") int size) throws IOException {
        List<String> recent = searchQueryService.getRecentSearches(customerId, size);
        return ResponseEntity.ok(recent);
    }

    @GetMapping("/analytics")
    public ResponseEntity<Map<String, Object>> searchAnalytics(
            @RequestParam String startDate,
            @RequestParam String endDate) throws IOException {
        Map<String, Object> analytics = searchQueryService.getSearchAnalytics(startDate, endDate);
        return ResponseEntity.ok(analytics);
    }
}

// ==================== GlobalExceptionHandler.java ====================
package com.ecommerce.search.controller;

import lombok.extern.slf4j.Slf4j;
import org.elasticsearch.ElasticsearchException;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.validation.FieldError;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

import java.io.IOException;
import java.util.HashMap;
import java.util.Map;

@RestControllerAdvice
@Slf4j
public class GlobalExceptionHandler {

    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ResponseEntity<Map<String, Object>> handleValidationExceptions(MethodArgumentNotValidException ex) {
        Map<String, Object> response = new HashMap<>();
        Map<String, String> errors = new HashMap<>();
        ex.getBindingResult().getAllErrors().forEach(error -> {
            String fieldName = ((FieldError) error).getField();
            String errorMessage = error.getDefaultMessage();
            errors.put(fieldName, errorMessage);
        });
        response.put("status", "VALIDATION_ERROR");
        response.put("errors", errors);
        return ResponseEntity.badRequest().body(response);
    }

    @ExceptionHandler(ElasticsearchException.class)
    public ResponseEntity<Map<String, String>> handleElasticsearchException(ElasticsearchException ex) {
        log.error("Elasticsearch error", ex);
        return ResponseEntity.status(HttpStatus.SERVICE_UNAVAILABLE)
            .body(Map.of("status", "ERROR", "message", "Search service temporarily unavailable"));
    }

    @ExceptionHandler(IOException.class)
    public ResponseEntity<Map<String, String>> handleIOException(IOException ex) {
        log.error("IO error communicating with Elasticsearch", ex);
        return ResponseEntity.status(HttpStatus.SERVICE_UNAVAILABLE)
            .body(Map.of("status", "ERROR", "message", "Search service temporarily unavailable"));
    }

    @ExceptionHandler(SecurityException.class)
    public ResponseEntity<Map<String, String>> handleSecurityException(SecurityException ex) {
        log.error("Security error", ex);
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
            .body(Map.of("status", "ERROR", "message", "Configuration error - contact administrator"));
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<Map<String, String>> handleGenericException(Exception ex) {
        log.error("Unexpected error", ex);
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
            .body(Map.of("status", "ERROR", "message", "An unexpected error occurred"));
    }
}

