// ==================== HealthCheckController.java ====================
package com.ecommerce.search.controller;

import lombok.RequiredArgsConstructor;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.io.IOException;
import java.util.Map;

@RestController
@RequestMapping("/api/health")
@RequiredArgsConstructor
public class HealthCheckController {

    private final RestHighLevelClient client;

    @GetMapping
    public ResponseEntity<Map<String, String>> health() {
        try {
            boolean ping = client.ping(RequestOptions.DEFAULT);
            if (ping) {
                return ResponseEntity.ok(Map.of("status", "UP", "elasticsearch", "connected"));
            } else {
                return ResponseEntity.status(503)
                    .body(Map.of("status", "DOWN", "elasticsearch", "not responding"));
            }
        } catch (IOException e) {
            return ResponseEntity.status(503)
                .body(Map.of("status", "DOWN", "elasticsearch", "connection failed"));
        }
    }
}

