package com.ecommerce.search.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.SerializationFeature;
import com.fasterxml.jackson.datatype.jsr310.JavaTimeModule;

@Configuration
public class AppConfig {

    @Bean
    public ObjectMapper objectMapper() {
        ObjectMapper mapper = new ObjectMapper();
        mapper.registerModule(new JavaTimeModule());
        mapper.disable(SerializationFeature.WRITE_DATES_AS_TIMESTAMPS);
        return mapper;
    }
}

// ==================== ElasticsearchConnectionValidator.java ====================
package com.ecommerce.search.config;

import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.context.event.ApplicationReadyEvent;
import org.springframework.context.event.EventListener;
import org.springframework.stereotype.Component;

@Component
@Slf4j
public class ElasticsearchConnectionValidator {

    @Value("${elasticsearch.scheme}")
    private String scheme;

    @Value("${elasticsearch.host}")
    private String host;

    @Value("${elasticsearch.port}")
    private int port;

    @EventListener(ApplicationReadyEvent.class)
    public void validateConnection() {
        if (!"https".equalsIgnoreCase(scheme)) {
            log.error("SECURITY VIOLATION: Elasticsearch is configured with unencrypted connection scheme '{}'. " +
                "Only HTTPS connections are permitted.", scheme);
            throw new SecurityException(
                "Elasticsearch must use HTTPS. Unencrypted connections are not allowed. " +
                "Set elasticsearch.scheme=https in your configuration."
            );
        }

        log.info("Elasticsearch connection validated: using encrypted HTTPS connection to {}:{}", host, port);
    }
}